#include <stdio.h>
int characterReplacement(char * s, int k) {
    int max_length = 0;
    for (int i = 0; i < strlen(s); i++) {
        int freq[26] = {0};
        int max_freq = 0;
        for (int j = i; j < strlen(s); j++) {
            freq[s[j] - 'A']++;
            max_freq = (max_freq > freq[s[j] - 'A']) ? max_freq : freq[s[j] - 'A'];
            int window_len = j - i + 1;
            int replace = window_len - max_freq;
            if (replace <= k) {
                max_length = (max_length > window_len) ? max_length : window_len;
            }
        }
    }
    return max_length;
}

